<template>
  <div class="workflow-list-container">
    <div class="page-header">
      <h1>工作流列表</h1>
      <div class="header-actions">
        <el-button type="primary" @click="$router.push('/workflow/create')">
          <el-icon><plus /></el-icon> 创建新工作流
        </el-button>
        <el-button type="success" @click="showTemplates">
          <el-icon><files /></el-icon> 从模板创建
        </el-button>
      </div>
    </div>

    <el-card class="workflow-filters">
      <el-form :inline="true" :model="filters" class="filters-form">
        <el-form-item label="搜索工作流">
          <el-input v-model="filters.search" placeholder="输入名称或描述搜索" clearable />
        </el-form-item>
        
        <el-form-item label="类型">
          <el-select v-model="filters.workflow_type" placeholder="全部类型" clearable>
            <el-option label="企业工作流" value="enterprise" />
            <el-option label="主播工作流" value="streamer" />
            <el-option label="通用工作流" value="general" />
          </el-select>
        </el-form-item>
        
        <el-form-item label="标签">
          <el-select v-model="filters.tags" placeholder="全部标签" multiple clearable>
            <el-option 
              v-for="tag in availableTags" 
              :key="tag" 
              :label="tag" 
              :value="tag" 
            />
          </el-select>
        </el-form-item>
        
        <el-form-item>
          <el-checkbox v-model="filters.show_templates">显示模板</el-checkbox>
        </el-form-item>
        
        <el-form-item>
          <el-button type="primary" @click="fetchWorkflows">
            <el-icon><search /></el-icon> 搜索
          </el-button>
          <el-button @click="resetFilters">
            <el-icon><refresh /></el-icon> 重置
          </el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <el-card v-loading="isLoading">
      <template #header>
        <div class="card-header">
          <h3>工作流列表</h3>
          <el-button 
            link 
            type="primary" 
            @click="fetchWorkflows">
            <el-icon><refresh /></el-icon> 刷新
          </el-button>
        </div>
      </template>

      <el-alert
        v-if="error"
        :title="error"
        type="error"
        :closable="false"
        show-icon
      />

      <!-- 工作流列表 -->
      <div class="workflow-list">
        <el-empty v-if="filteredWorkflows.length === 0" description="没有找到工作流" />
        
        <el-row :gutter="20">
          <el-col :xs="24" :sm="12" :md="8" :lg="6" v-for="workflow in filteredWorkflows" :key="workflow.id">
            <el-card class="workflow-card" shadow="hover">
              <template #header>
                <div class="workflow-header">
                  <span class="workflow-name">{{ workflow.name }}</span>
                  <el-tag size="small" :type="getWorkflowTypeTag(workflow.workflow_type)">
                    {{ getWorkflowTypeLabel(workflow.workflow_type) }}
                  </el-tag>
                </div>
              </template>
              
              <div class="workflow-content">
                <p class="workflow-description">{{ workflow.description || '无描述' }}</p>
                
                <div class="workflow-meta">
                  <div class="meta-item">
                    <el-icon><calendar /></el-icon>
                    <span>{{ formatDate(workflow.created_at) }}</span>
                  </div>
                  
                  <div class="meta-item" v-if="workflow.last_run_at">
                    <el-icon><timer /></el-icon>
                    <span>最近运行: {{ formatDate(workflow.last_run_at) }}</span>
                  </div>
                  
                  <div class="meta-item">
                    <el-icon><user /></el-icon>
                    <span>{{ workflow.user_name || '未知用户' }}</span>
                  </div>
                </div>
                
                <div class="workflow-actions">
                  <el-button-group>
                    <el-button size="small" @click="$router.push(`/workflow/${workflow.id}`)">
                      <el-icon><view /></el-icon>
                      查看
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="primary"
                      @click="$router.push(`/workflow/${workflow.id}/edit`)"
                      v-if="workflow.can_edit"
                    >
                      <el-icon><edit /></el-icon>
                      编辑
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="success"
                      @click="startWorkflow(workflow.id)"
                    >
                      <el-icon><video-play /></el-icon>
                      运行
                    </el-button>
                    
                    <el-button
                      size="small"
                      type="danger"
                      @click="confirmDeleteWorkflow(workflow)"
                      v-if="workflow.can_delete"
                    >
                      <el-icon><delete /></el-icon>
                    </el-button>
                  </el-button-group>
                </div>
              </div>
            </el-card>
          </el-col>
        </el-row>
      </div>
    </el-card>

    <!-- 删除确认对话框 -->
    <el-dialog
      v-model="deleteDialogVisible"
      title="确认删除"
      width="30%"
    >
      <span>确定要删除工作流 "{{ workflowToDelete?.name }}" 吗？此操作不可撤销。</span>
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="deleteDialogVisible = false">取消</el-button>
          <el-button type="danger" @click="deleteWorkflow">确认删除</el-button>
        </span>
      </template>
    </el-dialog>

    <!-- 启动工作流对话框 -->
    <el-dialog
      v-model="startDialogVisible"
      title="启动工作流"
      width="50%"
    >
      <el-form label-position="top">
        <el-form-item label="输入参数 (JSON格式)" v-if="currentWorkflow?.parameters?.length">
          <el-input
            v-model="startParameters"
            type="textarea"
            :rows="5"
            placeholder="{}"
          />
        </el-form-item>
        <el-alert
          v-else
          title="此工作流没有需要输入的参数"
          type="info"
          :closable="false"
        />
      </el-form>
      
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="startDialogVisible = false">取消</el-button>
          <el-button type="primary" @click="confirmStartWorkflow">启动</el-button>
        </span>
      </template>
    </el-dialog>

    <!-- 工作流执行对话框 -->
    <el-dialog
      v-model="executeDialogVisible"
      title="执行工作流"
      width="50%"
    >
      <template v-if="selectedWorkflow">
        <p><strong>工作流名称:</strong> {{ selectedWorkflow.name }}</p>
        <p><strong>描述:</strong> {{ selectedWorkflow.description }}</p>
        
        <el-divider content-position="left">输入参数</el-divider>
        
        <el-form ref="executeForm" :model="executeParams" label-position="top">
          <el-form-item 
            v-for="(param, index) in workflowParams" 
            :key="index"
            :label="param.name || `参数 ${index + 1}`"
            :prop="`params.${param.key}`"
          >
            <div class="param-description" v-if="param.description">
              {{ param.description }}
            </div>
            <el-input 
              v-if="param.type === 'string'" 
              v-model="executeParams.params[param.key]" 
              :placeholder="param.placeholder || '请输入参数值'"
            />
            <el-input-number 
              v-else-if="param.type === 'number'" 
              v-model="executeParams.params[param.key]" 
              :placeholder="param.placeholder || '请输入数值'"
              class="full-width"
            />
            <el-switch 
              v-else-if="param.type === 'boolean'" 
              v-model="executeParams.params[param.key]" 
              :active-text="param.trueLabel || '是'"
              :inactive-text="param.falseLabel || '否'"
            />
            <el-input 
              v-else
              v-model="executeParams.params[param.key]" 
              :placeholder="param.placeholder || '请输入参数值'"
            />
          </el-form-item>
        </el-form>
      </template>
      
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="executeDialogVisible = false">取消</el-button>
          <el-button type="primary" @click="runWorkflow" :loading="isExecuting">执行</el-button>
        </span>
      </template>
    </el-dialog>
    
    <!-- 模板对话框 -->
    <el-dialog
      v-model="templateDialogVisible"
      title="工作流模板库"
      width="70%"
    >
      <div class="template-filters">
        <el-input 
          v-model="templateFilters.search" 
          placeholder="搜索模板" 
          prefix-icon="Search"
          clearable
          @input="filterTemplates"
        />
        <el-select
          v-model="templateFilters.tag"
          placeholder="按标签筛选"
          clearable
          @change="filterTemplates"
        >
          <el-option
            v-for="tag in availableTags"
            :key="tag"
            :label="tag"
            :value="tag"
          />
        </el-select>
      </div>
      
      <div class="templates-wrapper">
        <el-empty v-if="filteredTemplates.length === 0" description="没有找到匹配的模板" />
        
        <div v-else class="templates-grid">
          <el-card 
            v-for="template in filteredTemplates" 
            :key="template.id"
            class="template-card"
            :body-style="{ padding: '0px' }"
            shadow="hover"
          >
            <div class="template-header">
              <h4>{{ template.name }}</h4>
              <div class="template-tags">
                <el-tag 
                  v-for="tag in template.tags" 
                  :key="tag" 
                  size="small" 
                  effect="plain"
                >
                  {{ tag }}
                </el-tag>
              </div>
            </div>
            <div class="template-body">
              <p class="template-description">{{ template.description || '无描述' }}</p>
              <div class="template-info">
                <span>步骤数: {{ getTemplateStepsCount(template) }}</span>
                <span>类型: {{ getWorkflowTypeLabel(template.workflow_type) }}</span>
              </div>
            </div>
            <div class="template-footer">
              <el-button type="primary" @click="createFromTemplate(template)">
                使用此模板
              </el-button>
              <el-button type="info" plain @click="viewWorkflow(template)">
                查看详情
              </el-button>
            </div>
          </el-card>
        </div>
      </div>
    </el-dialog>
    
    <!-- 保存为模板对话框 -->
    <el-dialog
      v-model="saveTemplateDialogVisible"
      title="保存为模板"
      width="50%"
    >
      <el-form ref="templateForm" :model="templateForm" :rules="templateRules" label-position="top">
        <el-form-item label="模板名称" prop="name">
          <el-input v-model="templateForm.name" placeholder="请输入模板名称" />
        </el-form-item>
        
        <el-form-item label="描述" prop="description">
          <el-input 
            v-model="templateForm.description" 
            type="textarea" 
            :rows="3" 
            placeholder="请输入模板描述"
          />
        </el-form-item>
        
        <el-form-item label="标签" prop="tags">
          <el-select
            v-model="templateForm.tags"
            multiple
            filterable
            allow-create
            default-first-option
            placeholder="请选择或创建标签"
            class="full-width"
          >
            <el-option
              v-for="tag in availableTags"
              :key="tag"
              :label="tag"
              :value="tag"
            />
          </el-select>
        </el-form-item>
      </el-form>
      
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="saveTemplateDialogVisible = false">取消</el-button>
          <el-button type="primary" @click="saveTemplate">保存</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script>
import { ref, reactive, computed, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { useWorkflowStore } from '@/store/workflow'
import { ElMessage, ElMessageBox } from 'element-plus'
import {
  Plus,
  Search,
  Refresh,
  View,
  Edit,
  Delete,
  VideoPlay,
  Calendar,
  Timer,
  User,
  Star,
  DocumentCopy,
  Files
} from '@element-plus/icons-vue'

export default {
  name: 'WorkflowList',
  components: {
    Plus,
    Search,
    Refresh,
    View,
    Edit,
    Delete,
    VideoPlay,
    Calendar,
    Timer,
    User,
    Star,
    DocumentCopy,
    Files
  },
  setup() {
    const router = useRouter()
    const workflowStore = useWorkflowStore()
    
    // 状态
    const filters = reactive({
      search: '',
      workflow_type: '',
      show_templates: false,
      tags: []
    })
    
    const executeDialogVisible = ref(false)
    const deleteDialogVisible = ref(false)
    const templateDialogVisible = ref(false)
    const saveTemplateDialogVisible = ref(false)
    
    const selectedWorkflow = ref(null)
    const executeParams = reactive({
      params: {}
    })
    
    const isExecuting = ref(false)
    
    // 模板状态
    const templateFilters = reactive({
      search: '',
      tag: ''
    })
    
    const templateForm = reactive({
      id: null,
      name: '',
      description: '',
      tags: []
    })
    
    const templateRules = {
      name: [
        { required: true, message: '请输入模板名称', trigger: 'blur' }
      ]
    }
    
    // 状态数据
    const searchQuery = ref('')
    const typeFilter = ref('')
    const onlyShowMine = ref(false)
    const startDialogVisible = ref(false)
    const workflowToDelete = ref(null)
    const workflowToStart = ref(null)
    const startParameters = ref('{}')
    
    // 计算属性
    const isLoading = computed(() => workflowStore.isLoading)
    const error = computed(() => workflowStore.error)
    const workflows = computed(() => workflowStore.workflows)
    const currentWorkflow = computed(() => workflowStore.currentWorkflow)
    
    const filteredWorkflows = computed(() => {
      let result = [...workflows.value]
      
      // 搜索过滤
      if (filters.search) {
        const searchLower = filters.search.toLowerCase()
        result = result.filter(w => 
          (w.name && w.name.toLowerCase().includes(searchLower)) || 
          (w.description && w.description.toLowerCase().includes(searchLower))
        )
      }
      
      // 类型过滤
      if (filters.workflow_type) {
        result = result.filter(w => w.workflow_type === filters.workflow_type)
      }
      
      // 标签过滤
      if (filters.tags && filters.tags.length > 0) {
        result = result.filter(w => 
          w.tags && filters.tags.every(tag => w.tags.includes(tag))
        )
      }
      
      // 模板过滤
      if (!filters.show_templates) {
        result = result.filter(w => !w.is_template)
      }
      
      return result
    })
    
    const templates = computed(() => {
      return workflows.value.filter(w => w.is_template)
    })
    
    const filteredTemplates = computed(() => {
      let result = [...templates.value]
      
      // 搜索过滤
      if (templateFilters.search) {
        const searchLower = templateFilters.search.toLowerCase()
        result = result.filter(t => 
          (t.name && t.name.toLowerCase().includes(searchLower)) || 
          (t.description && t.description.toLowerCase().includes(searchLower))
        )
      }
      
      // 标签过滤
      if (templateFilters.tag) {
        result = result.filter(t => 
          t.tags && t.tags.includes(templateFilters.tag)
        )
      }
      
      return result
    })
    
    // 获取所有可用标签
    const availableTags = computed(() => {
      const tags = new Set()
      workflows.value.forEach(workflow => {
        if (workflow.tags && Array.isArray(workflow.tags)) {
          workflow.tags.forEach(tag => tags.add(tag))
        }
      })
      return Array.from(tags)
    })
    
    // 工作流参数 - 从工作流定义中提取
    const workflowParams = computed(() => {
      if (!selectedWorkflow.value || !selectedWorkflow.value.definition) {
        return []
      }
      
      // 尝试提取工作流参数定义
      try {
        let definition = selectedWorkflow.value.definition
        if (typeof definition === 'string') {
          definition = JSON.parse(definition)
        }
        
        return definition.parameters || []
      } catch (err) {
        console.error('解析工作流参数失败', err)
        return []
      }
    })
    
    // 获取模板步骤数
    const getTemplateStepsCount = (template) => {
      if (!template.definition) return 0
      
      try {
        let definition = template.definition
        if (typeof definition === 'string') {
          definition = JSON.parse(definition)
        }
        
        return definition.steps ? definition.steps.length : 0
      } catch (err) {
        return 0
      }
    }
    
    // 方法
    const fetchWorkflows = async () => {
      await workflowStore.fetchWorkflows()
    }
    
    const confirmDeleteWorkflow = (workflow) => {
      workflowToDelete.value = workflow
      deleteDialogVisible.value = true
    }
    
    const deleteWorkflow = async () => {
      if (!workflowToDelete.value) return
      
      try {
        const success = await workflowStore.deleteWorkflow(workflowToDelete.value.id)
        if (success) {
          ElMessage.success('工作流删除成功')
          deleteDialogVisible.value = false
          workflowToDelete.value = null
        }
      } catch (error) {
        ElMessage.error('删除工作流失败')
      }
    }
    
    const startWorkflow = async (id) => {
      workflowToStart.value = id
      startParameters.value = '{}'
      
      // 获取工作流详情以获取参数信息
      await workflowStore.fetchWorkflow(id)
      startDialogVisible.value = true
    }
    
    const confirmStartWorkflow = async () => {
      if (!workflowToStart.value) return
      
      try {
        // 解析JSON参数
        let parameters = {}
        try {
          parameters = JSON.parse(startParameters.value)
        } catch (e) {
          ElMessage.error('参数格式不正确，请输入有效的JSON')
          return
        }
        
        const instance = await workflowStore.startWorkflowInstance(workflowToStart.value, parameters)
        ElMessage.success('工作流启动成功')
        startDialogVisible.value = false
        
        // 跳转到实例详情页
        router.push(`/workflow/instance/${instance.id}`)
      } catch (error) {
        ElMessage.error('启动工作流失败: ' + (error.message || '未知错误'))
      }
    }
    
    // 重置过滤条件
    const resetFilters = () => {
      filters.search = ''
      filters.workflow_type = ''
      filters.tags = []
      filters.show_templates = false
      fetchWorkflows()
    }
    
    // 执行工作流
    const executeWorkflow = (workflow) => {
      selectedWorkflow.value = workflow
      executeParams.params = {}
      
      // 初始化默认参数值
      workflowParams.value.forEach(param => {
        if (param.key && param.defaultValue !== undefined) {
          executeParams.params[param.key] = param.defaultValue
        } else if (param.key) {
          // 根据类型设置默认空值
          if (param.type === 'number') {
            executeParams.params[param.key] = 0
          } else if (param.type === 'boolean') {
            executeParams.params[param.key] = false
          } else {
            executeParams.params[param.key] = ''
          }
        }
      })
      
      executeDialogVisible.value = true
    }
    
    // 运行工作流
    const runWorkflow = async () => {
      if (!selectedWorkflow.value) return
      
      isExecuting.value = true
      
      try {
        const instance = await workflowStore.startWorkflowInstance(
          selectedWorkflow.value.id, 
          executeParams.params
        )
        
        ElMessage.success('工作流启动成功')
        executeDialogVisible.value = false
        
        // 跳转到实例详情页
        if (instance && instance.instance_id) {
          router.push(`/workflow/instances/${instance.instance_id}`)
        }
      } catch (error) {
        ElMessage.error('工作流启动失败: ' + (error.message || '未知错误'))
      } finally {
        isExecuting.value = false
      }
    }
    
    // 显示模板库
    const showTemplates = () => {
      templateFilters.search = ''
      templateFilters.tag = ''
      templateDialogVisible.value = true
    }
    
    // 筛选模板
    const filterTemplates = () => {
      // 由计算属性自动处理
    }
    
    // 从模板创建
    const createFromTemplate = (template) => {
      if (!template) return
      
      // 准备克隆数据
      const clonedWorkflow = {
        name: `基于 ${template.name} 的工作流`,
        description: template.description,
        workflow_type: template.workflow_type,
        is_public: false,
        definition: template.definition,
        tags: [...(template.tags || [])],
        is_template: false,
        template_id: template.id
      }
      
      // 创建新工作流
      workflowStore.saveWorkflow(clonedWorkflow).then((newWorkflow) => {
        if (newWorkflow && newWorkflow.id) {
          ElMessage.success('成功从模板创建工作流')
          templateDialogVisible.value = false
          router.push(`/workflow/${newWorkflow.id}/edit`)
        }
      }).catch((error) => {
        ElMessage.error('从模板创建工作流失败: ' + (error.message || '未知错误'))
      })
    }
    
    // 保存为模板
    const saveTemplate = async () => {
      if (!templateForm.id) return
      
      try {
        // 获取原始工作流
        await workflowStore.fetchWorkflow(templateForm.id)
        const originalWorkflow = workflowStore.currentWorkflow
        
        if (!originalWorkflow) {
          ElMessage.error('获取原始工作流失败')
          return
        }
        
        // 创建模板
        const templateData = {
          name: templateForm.name,
          description: templateForm.description,
          workflow_type: originalWorkflow.workflow_type,
          is_public: true,
          definition: originalWorkflow.definition,
          tags: templateForm.tags,
          is_template: true
        }
        
        await workflowStore.saveWorkflow(templateData)
        ElMessage.success('工作流已保存为模板')
        saveTemplateDialogVisible.value = false
        fetchWorkflows()
      } catch (error) {
        ElMessage.error('保存模板失败: ' + (error.message || '未知错误'))
      }
    }
    
    // 工具函数
    const formatDate = (dateString) => {
      if (!dateString) return '未知'
      const date = new Date(dateString)
      return date.toLocaleString('zh-CN')
    }
    
    const getWorkflowTypeLabel = (type) => {
      const types = {
        'enterprise': '企业',
        'streamer': '主播',
        'general': '通用'
      }
      return types[type] || '未知'
    }
    
    const getWorkflowTypeTag = (type) => {
      const types = {
        'enterprise': 'success',
        'streamer': 'warning',
        'general': 'info'
      }
      return types[type] || ''
    }
    
    // 生命周期钩子
    onMounted(() => {
      fetchWorkflows()
    })
    
    return {
      workflows,
      filteredWorkflows,
      isLoading,
      filters,
      executeDialogVisible,
      deleteDialogVisible,
      templateDialogVisible,
      saveTemplateDialogVisible,
      selectedWorkflow,
      executeParams,
      workflowParams,
      isExecuting,
      templates,
      filteredTemplates,
      templateFilters,
      templateForm,
      templateRules,
      availableTags,
      fetchWorkflows,
      viewWorkflow,
      editWorkflow,
      confirmDelete,
      deleteWorkflow,
      executeWorkflow,
      runWorkflow,
      resetFilters,
      getWorkflowTypeLabel,
